function calculate({ averageDailyRevenue, grossProfitMargin, fullInterruptionDays, partialInterruptionWeeks, partialInterruptionRevenueLossPercentage, extraExpensesMitigation, extraExpensesOperational, supplyChainImpactPercentage, insuranceDeductible }) {

  // Input validation and sanitization
  averageDailyRevenue = Math.max(0, parseFloat(averageDailyRevenue || 0));
  grossProfitMargin = Math.max(0, Math.min(100, parseFloat(grossProfitMargin || 0)));
  fullInterruptionDays = Math.max(0, Math.floor(parseFloat(fullInterruptionDays || 0)));
  partialInterruptionWeeks = Math.max(0, Math.floor(parseFloat(partialInterruptionWeeks || 0)));
  partialInterruptionRevenueLossPercentage = Math.max(0, Math.min(100, parseFloat(partialInterruptionRevenueLossPercentage || 0)));
  extraExpensesMitigation = Math.max(0, parseFloat(extraExpensesMitigation || 0));
  extraExpensesOperational = Math.max(0, parseFloat(extraExpensesOperational || 0));
  supplyChainImpactPercentage = Math.max(0, Math.min(100, parseFloat(supplyChainImpactPercentage || 0)));
  insuranceDeductible = parseFloat(insuranceDeductible || 0);

  const dailyGrossProfit = averageDailyRevenue * (grossProfitMargin / 100);

  // 1. Calculate Gross Profit Loss during Full Interruption
  const fullInterruptionLoss = dailyGrossProfit * fullInterruptionDays;

  // 2. Calculate Gross Profit Loss during Partial Interruption (Recovery Phase)
  // Assuming partial interruption loss applies to the *remaining* revenue after the percentage loss
  const partialInterruptionDays = partialInterruptionWeeks * 7;
  const dailyRevenueLossDuringPartial = averageDailyRevenue * (partialInterruptionRevenueLossPercentage / 100);
  const partialInterruptionGrossProfitLoss = dailyRevenueLossDuringPartial * (grossProfitMargin / 100) * partialInterruptionDays;

  // 3. Calculate additional Gross Profit Loss due to Supply Chain Disruption
  // This impact is assumed to apply across the entire period of disruption (full + partial).
  // It's a reduction in *potential* revenue that turns into gross profit loss.
  const totalDisruptionDays = fullInterruptionDays + partialInterruptionDays;
  const supplyChainRevenueLoss = averageDailyRevenue * (supplyChainImpactPercentage / 100) * totalDisruptionDays;
  const supplyChainGrossProfitLoss = supplyChainRevenueLoss * (grossProfitMargin / 100);

  // 4. Sum Extra Expenses
  const totalExtraExpenses = extraExpensesMitigation + extraExpensesOperational;

  // 5. Calculate Total Estimated Gross Profit Loss
  const totalGrossProfitLoss = fullInterruptionLoss + partialInterruptionGrossProfitLoss + supplyChainGrossProfitLoss;

  // 6. Calculate Total Estimated Business Interruption Loss
  const totalEstimatedBusinessInterruptionLoss = totalGrossProfitLoss + totalExtraExpenses;

  // 7. Calculate Net Loss After Insurance Deductible
  let netLossAfterInsurance = totalEstimatedBusinessInterruptionLoss;
  if (insuranceDeductible > 0) {
    netLossAfterInsurance = Math.max(0, totalEstimatedBusinessInterruptionLoss - insuranceDeductible);
  }

  return {
    totalGrossProfitLoss: totalGrossProfitLoss,
    totalExtraExpenses: totalExtraExpenses,
    totalEstimatedBusinessInterruptionLoss: totalEstimatedBusinessInterruptionLoss,
    netLossAfterInsurance: netLossAfterInsurance
  };
}
